  Future<void> _onSubmitted(
    LoginSubmitted event,
    Emitter<LoginState> emit,
  ) async {
    emit(const LoginLoading());
    final result = await _authRepository.login(event.email, event.password);
    switch (result) {
      case Success(:final value):
// ctx:auth_2fa_email:begin
        if (value.requiresTwoFactor) {
          emit(LoginRequiresTwoFactor(event.email, event.password));
          return;
        }
// ctx:auth_2fa_email:end
        emit(const LoginSuccess()); // Router redirect handles navigation.
      case Failure(:final error):
        emit(LoginFailure(AppException.from(error).userFriendlyMessage));
    }
  }

